#!/bin/bash
# Uninstall script for WinBox
# Generated by IntuneBrew

# Exit on error
set -e

echo "Uninstalling WinBox..."

# Check if running as root
if [ "$EUID" -ne 0 ]; then
  echo "Please run as root"
  exit 1
fi

# Kill application process if running
echo "Stopping WinBox if running..."
pkill -f "WinBox" 2>/dev/null || true

# Remove /Applications/WinBox.app
echo "Removing /Applications/WinBox.app..."
if [ -d "/Applications/WinBox.app" ]; then
    rm -rf "/Applications/WinBox.app" 2>/dev/null || true
elif [ -f "/Applications/WinBox.app" ]; then
    rm -f "/Applications/WinBox.app" 2>/dev/null || true
fi

# Remove $HOME/Library/Application Support/MikroTik/WinBox
echo "Removing $HOME/Library/Application Support/MikroTik/WinBox..."
if [ -d "$HOME/Library/Application Support/MikroTik/WinBox" ]; then
    rm -rf "$HOME/Library/Application Support/MikroTik/WinBox" 2>/dev/null || true
elif [ -f "$HOME/Library/Application Support/MikroTik/WinBox" ]; then
    rm -f "$HOME/Library/Application Support/MikroTik/WinBox" 2>/dev/null || true
fi

# Remove $HOME/Library/Caches/MikroTik/WinBox
echo "Removing $HOME/Library/Caches/MikroTik/WinBox..."
if [ -d "$HOME/Library/Caches/MikroTik/WinBox" ]; then
    rm -rf "$HOME/Library/Caches/MikroTik/WinBox" 2>/dev/null || true
elif [ -f "$HOME/Library/Caches/MikroTik/WinBox" ]; then
    rm -f "$HOME/Library/Caches/MikroTik/WinBox" 2>/dev/null || true
fi

# Remove $HOME/Library/Saved Application State/com.mikrotik.winbox.savedState
echo "Removing $HOME/Library/Saved Application State/com.mikrotik.winbox.savedState..."
if [ -d "$HOME/Library/Saved Application State/com.mikrotik.winbox.savedState" ]; then
    rm -rf "$HOME/Library/Saved Application State/com.mikrotik.winbox.savedState" 2>/dev/null || true
elif [ -f "$HOME/Library/Saved Application State/com.mikrotik.winbox.savedState" ]; then
    rm -f "$HOME/Library/Saved Application State/com.mikrotik.winbox.savedState" 2>/dev/null || true
fi

echo "Uninstallation complete!"
exit 0
